  ('locality-7c9828ae-moex-00161', 'locality-7c9828ae', 'locality-7c9828ae-moex-112-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於即時強制，下列敘述何者錯誤？', '["人民因執行機關依法實施即時強制，致其生命、身體或財產遭受特別損失時，得請求補償", "對於住宅、建築物或其他處所之進入，以人民之生命、身體、財產有迫切之危害，非進入不能救護者為限", "行政機關為阻止犯罪、危害之發生或避免急迫危險，而有即時處置之必要時，得為即時強制", "即時強制行為之對人管束，得視情況延長至48小時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "63c794400f58", "answer_pdf_sha1": "ae862658c350", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "407", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
