  ('locality-7c9828ae-moex-00164', 'locality-7c9828ae', 'locality-7c9828ae-moex-112-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於行政機關間請求協助，下列敘述何者錯誤？', '["行政機關執行職務時，得向所屬之下級機關請求職務協助", "行政執行機關於必要時，得依法請求其他機關協助", "對於在軍隊服役之軍人為行政送達者，應囑託該管軍事機關或長官為之", "由被請求機關協助執行，顯較經濟者，得請求職務協助"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "63c794400f58", "answer_pdf_sha1": "ae862658c350", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "407", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL)
